import{hsvToHex}from"/scripts/applets/applet.min.js";import{createDesmosGraphs,getColored3DCurve,getDesmosSlider}from"/scripts/src/desmos.min.js";import{raw}from"/scripts/src/main.min.js";export default function(){createDesmosGraphs({parametricCurveShaping:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-1.5,xmax:1.5,ymin:-1.5,ymax:1.5,zmin:-1.5,zmax:1.5},expressions:[{latex:raw`l(t) = (\cos(2t), \sin(2t), t)`,hidden:!0},...getColored3DCurve({pathFunction:t=>[t,0,0],pathFunctionDesmos:raw`(1 - s) (1, 0, 0)t + s l(6(t-0.5))`,minT:0,maxT:1,numSlices:100,colorFunction:([x])=>hsvToHex(1-.5*x,1,1)}),...getDesmosSlider({expression:"s = 0",min:0,max:1,secret:!1})]}})}